import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input, which can be obtained from a form submission
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by sanitizing and encoding it
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);
        String output = "Welcome, " + sanitizedInput;

        // Code that outputs the sanitized user input to a web page
        try {
            PrintWriter out = new PrintWriter("output.html", "UTF-8");
            out.println("<html><body>");
            out.println(output);
            out.println("</body></html>");
            out.close();
            System.out.println("Output file generated successfully.");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
